import{c as a,Q as t,j as r,m as s}from"./chunks/framework.BPKcPtvA.js";const g=JSON.parse('{"title":"Release Configuration","description":"","frontmatter":{},"headers":[],"relativePath":"guide/admin/release-configuration.md","filePath":"guide/admin/release-configuration.md","lastUpdated":1778862269000}'),o={name:"guide/admin/release-configuration.md"};function n(i,e,l,d,h,c){return t(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="release-configuration" tabindex="-1">Release Configuration <a class="header-anchor" href="#release-configuration" aria-label="Permalink to &quot;Release Configuration&quot;">​</a></h1><p><strong>Release Configuration</strong> is the global configuration for how releases behave on this platform. There is one config — everything on this page applies to every release.</p><h2 id="layout" tabindex="-1">Layout <a class="header-anchor" href="#layout" aria-label="Permalink to &quot;Layout&quot;">​</a></h2><p>Top to bottom: Product Version, Managed Services, Pipeline Stages, Approval Settings, SLA Thresholds, Escalation POC. A persistent header shows count badges (stages, services) and <strong>Save</strong> / <strong>Reset</strong> buttons.</p><p>If your edits include validation errors, an alert lists them above the sections and <strong>Save</strong> is disabled until they are fixed.</p><h2 id="product-version" tabindex="-1">Product Version <a class="header-anchor" href="#product-version" aria-label="Permalink to &quot;Product Version&quot;">​</a></h2><p>Current Version is a text input (e.g. <code>25.3.6</code>).</p><p>The product version advances automatically when a Feature or Hotfix release is created (semver bump). Edit here only to correct a mistake or initialise.</p><h2 id="managed-services" tabindex="-1">Managed Services <a class="header-anchor" href="#managed-services" aria-label="Permalink to &quot;Managed Services&quot;">​</a></h2><p>The services the pipeline operates on. Anything not listed here is ignored by releases.</p><ul><li>Type a service name in the input and click <strong>Add Service</strong> (or press Enter).</li><li>Services appear as removable badge chips.</li><li>Services are resolved by Kubernetes labels first, falling back to deployment name.</li></ul><h2 id="pipeline-stages" tabindex="-1">Pipeline Stages <a class="header-anchor" href="#pipeline-stages" aria-label="Permalink to &quot;Pipeline Stages&quot;">​</a></h2><p>The ordered sequence of stages.</p><p>Each row has:</p><ul><li><strong>Environment</strong> dropdown — predefined values (DEV, QA, UAT, STAGING, DEMO, PRE_PROD, PROD) plus any custom values already in use.</li><li><strong>Stage Order</strong> number input — stages with the same order run in <strong>parallel</strong>.</li><li><strong>Delete</strong> button.</li></ul><p>Click <strong>Add Stage</strong> to add a row.</p><p>Validation: no empty environments, no negative stage orders, no duplicates (same environment + same stage order).</p><h2 id="approval-settings" tabindex="-1">Approval Settings <a class="header-anchor" href="#approval-settings" aria-label="Permalink to &quot;Approval Settings&quot;">​</a></h2><h3 id="approval-mode" tabindex="-1">Approval mode <a class="header-anchor" href="#approval-mode" aria-label="Permalink to &quot;Approval mode&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Mode</th><th>Meaning</th></tr></thead><tbody><tr><td><strong>Disabled</strong></td><td>No approval required. Stages proceed automatically.</td></tr><tr><td><strong>All Instance SPOCs</strong></td><td>Every SPOC of every instance in the stage must approve.</td></tr><tr><td><strong>Any Instance SPOC</strong></td><td>One SPOC approval is enough.</td></tr></tbody></table><p>SPOCs are configured per instance — see the <strong>SPOCs</strong> tab on the Instance detail page.</p><h3 id="devops-trigger" tabindex="-1">DevOps trigger <a class="header-anchor" href="#devops-trigger" aria-label="Permalink to &quot;DevOps trigger&quot;">​</a></h3><p>A separate checkbox: <strong>Require DevOps trigger after SPOC approval</strong>. When on, an explicit human trigger is needed after SPOC approval before deployment actually starts. This is a second gate, not a replacement for approval.</p><h2 id="sla-thresholds" tabindex="-1">SLA Thresholds <a class="header-anchor" href="#sla-thresholds" aria-label="Permalink to &quot;SLA Thresholds&quot;">​</a></h2><p>Two columns: normal releases (feature / config) and hotfix releases. Each column has three inputs.</p><h3 id="normal-releases-days" tabindex="-1">Normal releases (days) <a class="header-anchor" href="#normal-releases-days" aria-label="Permalink to &quot;Normal releases (days)&quot;">​</a></h3><ul><li><strong>Reminder</strong> — when to nudge waiting approvers.</li><li><strong>Escalation</strong> — when to involve escalation contacts.</li><li><strong>Stalled</strong> — when to mark the release as stalled.</li></ul><h3 id="hotfix-releases-hours" tabindex="-1">Hotfix releases (hours) <a class="header-anchor" href="#hotfix-releases-hours" aria-label="Permalink to &quot;Hotfix releases (hours)&quot;">​</a></h3><p>Same three thresholds, but in hours — hotfixes are time-critical.</p><h2 id="escalation-poc" tabindex="-1">Escalation POC <a class="header-anchor" href="#escalation-poc" aria-label="Permalink to &quot;Escalation POC&quot;">​</a></h2><p>The list of contacts who get involved when a release breaches its SLA thresholds.</p><ul><li><strong>Add User</strong> dropdown searches active users.</li><li><strong>Add User</strong> button adds to the table.</li><li>The table shows User, Email, IDP User ID with a delete button per row.</li></ul><p>If no contacts are configured, the table shows a placeholder message — but a release that breaches SLA with no escalation contacts will simply not page anyone.</p><h2 id="saving" tabindex="-1">Saving <a class="header-anchor" href="#saving" aria-label="Permalink to &quot;Saving&quot;">​</a></h2><ul><li><strong>Save Configuration</strong> — disabled unless there are validation-free changes.</li><li><strong>Reset</strong> — discards your unsaved edits and reverts to the server state. Enabled only when there are unsaved edits.</li></ul><p>There is no inline / per-row save. All sections share one Save button.</p><h2 id="when-configuration-changes-take-effect" tabindex="-1">When configuration changes take effect <a class="header-anchor" href="#when-configuration-changes-take-effect" aria-label="Permalink to &quot;When configuration changes take effect&quot;">​</a></h2><ul><li><strong>Stages, services, approval, triggers, SLAs</strong> — apply to releases created <em>after</em> the save. Existing in-flight releases continue under the configuration they started with.</li><li><strong>Product version</strong> — takes effect on the next release.</li><li><strong>Escalation contacts</strong> — apply to alerts emitted after the save.</li></ul><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Treat the pipeline like infrastructure. Sketch it first, then build.</li><li>Parallel stages (same Stage Order) save wall time but multiply blast radius. For PROD, run sequentially.</li><li>Approval and trigger gates are cheap to add and slow to add later — turn them on for any stage that can break a customer.</li><li>Hotfix SLA thresholds in hours, normal in days. Do not paste the same numbers into both.</li></ul>',40)])])}const u=a(o,[["render",n]]);export{g as __pageData,u as default};
